namespace HaCreator.GUI.InstanceEditor{public partial class TileInstanceEditor:EditorBase{public TileInstance item;public TileInstanceEditor(TileInstance item){InitializeComponent();this.item=item;InstanceEditorDialogSupport.SetInt(xInput,item.X);InstanceEditorDialogSupport.SetInt(yInput,item.Y);InstanceEditorDialogSupport.SetInt(zInput,item.Z);pathLabel.Text=HaCreatorStateManager.CreateItemDescription(item);}protected override void cancelButton_Click(object s,EventArgs e)=>Close();protected override void okButton_Click(object s,EventArgs e){lock(item.Board.ParentControl){int x=InstanceEditorDialogSupport.GetInt(xInput,item.X),y=InstanceEditorDialogSupport.GetInt(yInput,item.Y),z=InstanceEditorDialogSupport.GetInt(zInput,item.Z);List<UndoRedoAction>a=new();if(x!=item.X||y!=item.Y){a.Add(UndoRedoManager.ItemMoved(item,new Microsoft.Xna.Framework.Point(item.X,item.Y),new Microsoft.Xna.Framework.Point(x,y)));item.Move(x,y);}if(z!=item.Z){a.Add(UndoRedoManager.ItemZChanged(item,item.Z,z));item.Z=z;item.Board.BoardItems.Sort();}if(a.Count>0)item.Board.UndoRedoMan.AddUndoBatch(a);}Close();}private void Cancel_Click(object s,RoutedEventArgs e)=>cancelButton_Click(s,EventArgs.Empty);private void Ok_Click(object s,RoutedEventArgs e)=>okButton_Click(s,EventArgs.Empty);}}
